plugins {
    id("com.android.application")
    id("org.jetbrains.kotlin.android")
    id("kotlin-kapt")
    id("com.google.dagger.hilt.android")
    id("com.google.devtools.ksp")
    id("org.jetbrains.kotlin.plugin.compose")

    // Добавляем плагины для статического анализа (согласно конституции)
    id("org.jlleitschuh.gradle.ktlint")
    id("io.gitlab.arturbosch.detekt")

    // Добавляем плагин Jacoco для покрытия тестами
    id("jacoco")
}

android {
    namespace = "com.safeplant"
    compileSdk = 34

    defaultConfig {
        applicationId = "com.safeplant"
        minSdk = 29
        targetSdk = 34
        versionCode = 1
        versionName = "1.0"

        testInstrumentationRunner = "androidx.test.runner.AndroidJUnitRunner"

        // Добавляем Jacoco для тестов
        testInstrumentationRunnerArguments["jacoco"] = "true"
    }

    buildTypes {
        debug {
            isMinifyEnabled = false
            enableAndroidTestCoverage = true
            enableAndroidTestCoverage = true
        }
        release {
            isMinifyEnabled = true
            proguardFiles(
                getDefaultProguardFile("proguard-android-optimize.txt"),
                "proguard-rules.pro",
            )
        }
    }

    // Добавляем конфигурацию Jacoco
    tasks.register("jacocoTestReport", JacocoReport::class.java) {
        dependsOn("testDebugUnitTest", "connectedDebugAndroidTest")

        sourceDirectories.setFrom(files("${project.projectDir}/src/main/java"))
        classDirectories.setFrom(files("${project.buildDir}/tmp/kotlin-classes/debug"))
        executionData.setFrom(files("${project.buildDir}/jacoco/testDebugUnitTest.exec", "${project.buildDir}/jacoco/testDebugUnitTest.exec"))

        reports {
            xml.required.set(true)
            html.required.set(true)
            csv.required.set(false)
        }
    }

    compileOptions {
        sourceCompatibility = JavaVersion.VERSION_17
        targetCompatibility = JavaVersion.VERSION_17
    }
    kotlinOptions {
        jvmTarget = "17"
    }
    buildFeatures {
        compose = true
    }
}

